# E2e tests for category: conversion
# Generated by html-to-markdown-e2e-generator — do not edit manually.

defmodule HtmlToMarkdown.ConversionTest do
  use ExUnit.Case

  test "blockquote_simple: Simple blockquote" do
    html = "<blockquote><p>Quote text</p></blockquote>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "> Quote text")
  end

  test "bold_and_italic: Nested bold and italic" do
    html = "<p><strong><em>both</em></strong></p>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "***both***")
  end

  test "bold_strong: Strong tag converts to bold" do
    html = "<p><strong>bold</strong></p>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "**bold**")
  end

  test "code_block: Code block with language" do
    html = "<pre><code class=\"language-python\">print('hello')</code></pre>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "```python")
    assert String.contains?(content, "print('hello')")
    assert String.contains?(content, "```")
  end

  test "heading_h1: H1 heading" do
    html = "<h1>Heading 1</h1>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) == "\# Heading 1"
  end

  test "heading_h2: H2 heading" do
    html = "<h2>Heading 2</h2>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) == "\#\# Heading 2"
  end

  test "heading_h3: H3 heading" do
    html = "<h3>Heading 3</h3>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) == "\#\#\# Heading 3"
  end

  test "heading_h4: H4 heading" do
    html = "<h4>Heading 4</h4>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) == "\#\#\#\# Heading 4"
  end

  test "heading_h5: H5 heading" do
    html = "<h5>Heading 5</h5>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) == "\#\#\#\#\# Heading 5"
  end

  test "heading_h6: H6 heading" do
    html = "<h6>Heading 6</h6>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.trim(content) == "\#\#\#\#\#\# Heading 6"
  end

  test "image_simple: Image with alt text" do
    html = "<img src=\"photo.jpg\" alt=\"A photo\">"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "![A photo](photo.jpg)")
  end

  test "inline_code: Inline code" do
    html = "<p>Use <code>console.log()</code> to debug</p>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "`console.log()`")
  end

  test "italic_em: Em tag converts to italic" do
    html = "<p><em>italic</em></p>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "*italic*")
  end

  test "link_simple: Simple link" do
    html = "<a href=\"https://example.com\">Example</a>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "[Example](https://example.com)")
  end

  test "link_with_title: Link with title attribute" do
    html = "<a href=\"https://example.com\" title=\"Example Site\">Example</a>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "[Example](https://example.com")
    assert String.contains?(content, "Example Site")
  end

  test "ordered_list: Ordered list" do
    html = "<ol><li>First</li><li>Second</li><li>Third</li></ol>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "1. First")
    assert String.contains?(content, "2. Second")
    assert String.contains?(content, "3. Third")
  end

  test "simple_table: Simple table with header" do
    html =
      "<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>"

    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "Name")
    assert String.contains?(content, "Age")
    assert String.contains?(content, "Alice")
    assert String.contains?(content, "30")
    assert String.contains?(content, "|")
    assert String.contains?(content, "---")
  end

  test "unordered_list: Unordered list" do
    html = "<ul><li>Item 1</li><li>Item 2</li><li>Item 3</li></ul>"
    {:ok, result} = HtmlToMarkdown.convert(html)
    content = result[:content] || ""

    assert String.contains?(content, "- Item 1")
    assert String.contains?(content, "- Item 2")
    assert String.contains?(content, "- Item 3")
  end
end
